_FUSED_SPMM_GEMM_RELU_AUTOTUNE_CONFIGS = [
    triton.Config(
        {"BLOCK_K1": bk1, "BLOCK_K2": bk2},
        num_stages=ns,
        num_warps=nw,
    )
    for bk1 in (32,64,128,256,)
    for bk2 in (32,64,)
    for nw in (2,4,8,)
    for ns in (2,4,)
]


@triton.autotune(
    configs=_FUSED_SPMM_GEMM_RELU_AUTOTUNE_CONFIGS,
    key=["M", "N", "K1", "K2"],
    cache_results=True,
)
